// Advanced rota planning patch: templates, copy/paste weeks, publish notifications, leave requests/approval conflicts.
(function(){
  const KEY='rotaAppUnifiedV2';
  const $=id=>document.getElementById(id);
  const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  const uid=p=>p+'_'+Math.random().toString(36).slice(2,9);
  const today=()=>new Date().toISOString().slice(0,10);
  const mins=t=>{let [h,m]=String(t||'00:00').split(':').map(Number);return (h||0)*60+(m||0)};
  const monday=d=>{d=new Date(d);let n=(d.getDay()+6)%7;d.setHours(0,0,0,0);d.setDate(d.getDate()-n);return d};
  const iso=d=>d.toISOString().slice(0,10);
  const plus=(d,n)=>{d=new Date(d);d.setDate(d.getDate()+n);return d};
  const weekDates=weekStart=>[0,1,2,3,4,5,6].map(n=>iso(plus(weekStart,n)));
  const currentWeekDates=()=>weekDates(typeof weekStart!=='undefined'?weekStart:monday(new Date()));
  const dateInRange=(date,start,end)=>date>=start&&date<=end;
  function ensureState(){
    state.rotaTemplates=state.rotaTemplates||[];
    state.copiedWeek=state.copiedWeek||null;
    state.publishedWeeks=state.publishedWeeks||{};
    state.adminAlerts=state.adminAlerts||[];
    state.leaveRequests=state.leaveRequests||[];
    state.shifts=state.shifts||[];
    state.alerts=state.alerts||[];
  }
  function persist(){ensureState();save();}
  function approvedLeaveFor(userId,date){return state.leaveRequests.find(r=>r.userId===userId&&r.status==='approved'&&dateInRange(date,r.startDate,r.endDate));}
  function leaveConflictForShift(shift){if(!shift.userId||shift.userId==='unassigned')return null;return approvedLeaveFor(shift.userId,shift.date);}
  function hasOverlap(shift,ignoreId){let start=mins(shift.start),end=mins(shift.end);if(end<=start)end+=1440;return state.shifts.find(s=>s.id!==ignoreId&&s.userId===shift.userId&&s.userId!=='unassigned'&&s.date===shift.date&&(()=>{let a=mins(s.start),b=mins(s.end);if(b<=a)b+=1440;return start<b&&a<end})());}
  function queueShiftNotification(shift,type='shift_update'){let u=state.users.find(x=>x.id===shift.userId);if(!u||!u.email||shift.userId==='unassigned')return;state.alerts.push({id:uid('alert'),type,userId:u.id,email:u.email,shiftId:shift.id,createdAt:new Date().toISOString(),fixedOn:true});}
  function weekShifts(dates=currentWeekDates()){return state.shifts.filter(s=>dates.includes(s.date));}
  function shiftToTemplateItem(shift,dates){return {dayOffset:dates.indexOf(shift.date),userId:shift.userId,section:shift.section,start:shift.start,end:shift.end,notes:shift.notes||'',unassigned:shift.userId==='unassigned'};}
  function templateToWeekShifts(template,targetWeekStart){let dates=weekDates(targetWeekStart);let conflicts=[];let shifts=(template.items||[]).map(item=>{let date=dates[item.dayOffset]||dates[0];let userId=item.userId;let conflict=userId&&userId!=='unassigned'?approvedLeaveFor(userId,date):null;if(conflict){conflicts.push({item,date,conflict});userId='unassigned'}return {id:uid('s'),userId,section:item.section,date,start:item.start,end:item.end,notes:conflict?((item.notes?item.notes+' · ':'')+'Cover needed: assigned user has approved leave.'):item.notes,unassigned:!!conflict||item.unassigned};});return {shifts,conflicts};}
  function removeWeek(dates){state.shifts=state.shifts.filter(s=>!dates.includes(s.date));}
  window.saveCurrentWeekAsTemplate=function(){ensureState();let name=prompt('Template name for this week');if(!name)return;let dates=currentWeekDates();let items=weekShifts(dates).map(s=>shiftToTemplateItem(s,dates));state.rotaTemplates.push({id:uid('tpl'),name:name.trim(),createdAt:new Date().toISOString(),items});persist();alert('Template saved.');renderAdmin();};
  window.loadTemplateToCurrentWeek=function(templateId){ensureState();let template=state.rotaTemplates.find(t=>t.id===templateId);if(!template)return;let replace=confirm('Replace the current week with this template? Cancel will add it on top instead.');let dates=currentWeekDates();if(replace)removeWeek(dates);let result=templateToWeekShifts(template,typeof weekStart!=='undefined'?weekStart:monday(new Date()));state.shifts.push(...result.shifts);if(result.conflicts.length){state.adminAlerts.push({id:uid('adminalert'),type:'template_leave_conflicts',createdAt:new Date().toISOString(),message:`${result.conflicts.length} shift(s) loaded as unassigned because the assigned user has approved leave.`});alert(`${result.conflicts.length} shift(s) loaded as unassigned because the assigned user has approved leave.`);}persist();renderRota();};
  window.copyCurrentWeek=function(){ensureState();let dates=currentWeekDates();state.copiedWeek={copiedAt:new Date().toISOString(),items:weekShifts(dates).map(s=>shiftToTemplateItem(s,dates))};persist();alert('Current week copied. Go to another week and paste it there.');};
  window.pasteCopiedWeek=function(){ensureState();if(!state.copiedWeek)return alert('No copied week found.');let replace=confirm('Replace this week with copied week? Cancel will add it on top instead.');let dates=currentWeekDates();if(replace)removeWeek(dates);let result=templateToWeekShifts(state.copiedWeek,typeof weekStart!=='undefined'?weekStart:monday(new Date()));state.shifts.push(...result.shifts);if(result.conflicts.length)alert(`${result.conflicts.length} shift(s) pasted as unassigned because the assigned user has approved leave.`);persist();renderRota();};
  window.publishCurrentWeek=function(){ensureState();let dates=currentWeekDates();let sections=[...new Set(state.shifts.filter(s=>dates.includes(s.date)).map(s=>s.section))];let selected=sections.filter(section=>confirm(`Send new/updated shift notifications for ${section}?`));let affected=state.shifts.filter(s=>dates.includes(s.date)&&selected.includes(s.section)&&s.userId&&s.userId!=='unassigned');affected.forEach(s=>queueShiftNotification(s,'published_shift_notice'));state.publishedWeeks[dates[0]]={publishedAt:new Date().toISOString(),sections:selected,shiftIds:affected.map(s=>s.id)};persist();alert(`${affected.length} fixed new/updated shift notification(s) queued.`);};
  window.submitLeaveRequest=function(){ensureState();let start=prompt('Leave start date (YYYY-MM-DD)',today());if(!start)return;let end=prompt('Leave end date (YYYY-MM-DD)',start);if(!end)return;let type=confirm('OK = paid holiday allowance. Cancel = unpaid time off.')?'paid':'unpaid';let days=Math.max(1,Math.round((new Date(end)-new Date(start))/86400000)+1);let req={id:uid('leave'),userId:state.currentUserId,startDate:start,endDate:end,type,status:'pending',days,hours:days*8,createdAt:new Date().toISOString()};state.leaveRequests.push(req);state.adminAlerts.push({id:uid('adminalert'),type:'leave_request',leaveRequestId:req.id,createdAt:new Date().toISOString(),message:`Leave request submitted by ${state.users.find(u=>u.id===req.userId)?.name||'user'} for ${start} to ${end}.`});persist();alert('Leave request sent to admin for approval.');render();};
  window.approveLeaveRequest=function(requestId){ensureState();let req=state.leaveRequests.find(r=>r.id===requestId);if(!req)return;req.status='approved';req.approvedAt=new Date().toISOString();let conflicts=state.shifts.filter(s=>s.userId===req.userId&&dateInRange(s.date,req.startDate,req.endDate));conflicts.forEach(s=>{s.originalUserId=s.userId;s.userId='unassigned';s.unassigned=true;s.notes=(s.notes? s.notes+' · ':'')+'Cover needed: approved leave.';});if(conflicts.length){state.adminAlerts.push({id:uid('adminalert'),type:'approved_leave_shift_conflict',leaveRequestId:req.id,createdAt:new Date().toISOString(),message:`Approved leave created ${conflicts.length} shift(s) requiring cover.`});alert(`Approved. ${conflicts.length} existing shift(s) now need cover and have been marked unassigned.`);}else alert('Leave approved. No rota conflicts found.');persist();renderAdmin();};
  window.rejectLeaveRequest=function(requestId){let req=state.leaveRequests.find(r=>r.id===requestId);if(!req)return;req.status='rejected';req.rejectedAt=new Date().toISOString();persist();renderAdmin();};
  function planningPanel(){ensureState();let dates=currentWeekDates();let templates=state.rotaTemplates||[];let requests=(state.leaveRequests||[]).filter(r=>r.status==='pending');let alerts=(state.adminAlerts||[]).slice(-5).reverse();return `<div class="planningPanel"><h2>Rota planning</h2><div class="planningActions"><button onclick="saveCurrentWeekAsTemplate()">Save current week as template</button><button onclick="copyCurrentWeek()" class="secondary">Copy current week</button><button onclick="pasteCopiedWeek()" class="secondary">Paste copied week here</button><button onclick="publishCurrentWeek()">Save & send notifications</button></div><div class="planningBox"><h3>Load template into current week</h3>${templates.length?templates.map(t=>`<div class="sectionRow"><span>${esc(t.name)}</span><button onclick="loadTemplateToCurrentWeek('${t.id}')">Load</button></div>`).join(''):'<p class="muted">No templates saved yet.</p>'}</div><div class="planningBox"><h3>Pending leave requests</h3>${requests.length?requests.map(r=>{let u=state.users.find(x=>x.id===r.userId)||{};return `<div class="sectionRow"><span>${esc(u.name||'User')} · ${r.startDate} to ${r.endDate} · ${r.type}</span><span><button onclick="approveLeaveRequest('${r.id}')">Approve</button> <button class="secondary" onclick="rejectLeaveRequest('${r.id}')">Reject</button></span></div>`}).join(''):'<p class="muted">No pending leave requests.</p>'}</div><div class="planningBox"><h3>Admin alerts</h3>${alerts.length?alerts.map(a=>`<p class="muted">${esc(a.message)}</p>`).join(''):'<p class="muted">No alerts.</p>'}</div></div>`;}
  const originalDrawAdmin=window.drawAdmin||drawAdmin;
  window.drawAdmin=function(){originalDrawAdmin();let inner=$('adminInner');if(!inner||state.adminPanel!=='shift')return;inner.insertAdjacentHTML('afterbegin',planningPanel());};
  drawAdmin=window.drawAdmin;
  const originalRenderProfileLeave=window.renderProfileLeave||renderProfileLeave;
  window.renderProfileLeave=function(u){originalRenderProfileLeave(u);let page=document.querySelector('.profilePage .panel');if(page&&u.id===state.currentUserId){page.insertAdjacentHTML('afterbegin','<button onclick="submitLeaveRequest()">Submit leave request</button>');}}
  renderProfileLeave=window.renderProfileLeave;
})();
